import { Project, SyntaxKind } from "ts-morph"

const project = new Project({ tsConfigFilePath: "tsconfig.json" })
const checker = project.getTypeChecker()

for (const sf of project.getSourceFiles()) {
  let changed = false
  // Fix 1: @typescript-eslint/restrict-template-expressions
  for (const templateSpan of sf.getDescendantsOfKind(SyntaxKind.TemplateSpan)) {
    const expr = templateSpan.getExpression()
    const type = expr.getType()
    if (type.isAny() || type.isUnknown() || type.isIntersection() || type.isUnion()) {
      // If it's a simple identifier, wrap in String()
      if (
        expr.getKind() === SyntaxKind.Identifier ||
        expr.getKind() === SyntaxKind.PropertyAccessExpression ||
        expr.getKind() === SyntaxKind.ElementAccessExpression ||
        expr.getKind() === SyntaxKind.CallExpression
      ) {
        if (!expr.getText().startsWith("String(")) {
          expr.replaceWithText(`String(${expr.getText()})`)
          changed = true
        }
      }
    }
  }

  // Fix 2: @typescript-eslint/no-explicit-any
  for (const anyKw of sf.getDescendantsOfKind(SyntaxKind.AnyKeyword)) {
    anyKw.replaceWithText("unknown")
    changed = true
  }

  if (changed) {
    sf.saveSync()
  }
}
console.log("Auto-fix complete.")

import { readFileSync } from "node:fs"
import { join } from "node:path"
import { skillDirs } from "../constants/skillDirs"
import { violations } from "../constants/violations"
import { parseFrontmatter } from "../lib/skills/utils/parseFrontmatter"

export async function main() {
  if (skillDirs.length === 0) {
    console.error("No source skills found under src/skills")
    process.exit(1)
  }
  for (const skillPath of skillDirs) {
    const skillMdPath = join(skillPath, "SKILL.md")
    const content = readFileSync(skillMdPath, "utf8")
    const fm = parseFrontmatter(content)
    if (!fm) {
      violations.push(`${skillMdPath}: missing frontmatter`)
      continue
    }

    const keys = Array.from(fm.fields.keys())
    const unexpected = keys.filter((key: string) => key !== "name" && key !== "description")
    if (unexpected.length > 0) {
      violations.push(`${skillMdPath}: unexpected frontmatter fields (${unexpected.join(", ")})`)
    }
  }
  if (violations.length > 0) {
    console.error("Skill frontmatter contract violations detected:")
    for (const violation of violations) {
      console.error(`- ${violation}`)
    }
    process.exit(1)
  }

  console.log(`Frontmatter contract OK (${skillDirs.length} skills).`)
}

if (import.meta.url === `file://${String(process.argv[1])}`) {
  main().catch(console.error)
}

import { readFileSync, writeFileSync } from "node:fs"
import { join } from "node:path"
import { buildLlmsTxt } from "./buildLlmsTxt"
import { LLMS_TXT } from "../constants/LLMS_TXT"
import { skillDirs } from "../constants/skillDirs"
import { skills } from "../constants/skills"
import { parseDescription } from "../lib/skills/utils/parseDescription"
import { parseFrontmatter } from "../lib/skills/utils/parseFrontmatter"
import { stripQuotes } from "../lib/skills/utils/stripQuotes"

export async function main() {
  if (skillDirs.length === 0) {
    console.error("No skill directories found under src/skills/")
    process.exit(1)
  }
  for (const skillPath of skillDirs) {
    const skillMd = join(skillPath, "SKILL.md")
    const content = readFileSync(skillMd, "utf-8")
    const fm = parseFrontmatter(content)
    if (!fm) continue

    const name = stripQuotes(fm.fields.get("name") || "")
    const description = parseDescription(fm.raw)
    if (!name || !description) continue

    skills.push({ name, description, skillPath })
  }

  skills.sort((a: { name: string }, b: { name: string }) => a.name.localeCompare(b.name))
  writeFileSync(LLMS_TXT, buildLlmsTxt(skills), "utf-8")

  console.log(`Wrote ${LLMS_TXT} (${skills.length} skills).`)
}

if (import.meta.url === `file://${String(process.argv[1])}`) {
  main().catch(console.error)
}

import { AGENTS_PATH } from "../constants/AGENTS_PATH"
import { CLAUDE_PATH } from "../constants/CLAUDE_PATH"
import { GEMINI_PATH } from "../constants/GEMINI_PATH"
import { verifyClaudeGoldenMaster } from "./verifyClaudeGoldenMaster"
import { verifyIndexOnlyOutput } from "./verifyIndexOnlyOutput"
import { WINDSURF_PATH } from "../constants/WINDSURF_PATH"
import { readIfExists } from "../lib/fs/utils/readIfExists"

export async function main() {
  const goldenOnly = process.argv.includes("--golden-only")
  const skipGolden = process.argv.includes("--skip-golden")
  if (!skipGolden) {
    const golden = await verifyClaudeGoldenMaster()
    if (!golden.ok) {
      console.error("[verify] Golden master check failed:", golden.error)
      process.exit(1)
    }
    console.log("[verify] CLAUDE.md golden master OK")
    if (goldenOnly) return
  }

  for (const [name, filePath, maxChars] of [
    ["CLAUDE.md", CLAUDE_PATH, 15_000],
    ["AGENTS.md", AGENTS_PATH, 50_000],
    ["GEMINI.md", GEMINI_PATH, 50_000],
    ["WINDSURF.md", WINDSURF_PATH, 50_000],
  ] as [string, string, number][]) {
    const content = await readIfExists(filePath)

    if (content && content.includes("## Rules index (router)")) {
      const result = verifyIndexOnlyOutput(content, {
        maxChars,
        minRefs: 40,
        ...(name === "GEMINI.md"
          ? {
              refPattern: /@\.agent\/(?:rules|workflows)\/[^\s`]+/g,
              refLabel: "@.agent/",
            }
          : {}),
      })
      if (!result.ok) {
        console.error(`[verify] DoD check failed for ${name}:`)
        result.errors.forEach((e: unknown) => {
          console.error("  -", e)
        })
        process.exit(1)
      }
      console.log(`[verify] ${name} DoD OK`)
    }
  }

  console.log("[verify] All checks passed.")
}

