export function getActivation(item: RuleItem) {
  const frontmatter = item.frontmatter ?? {}

  if (frontmatter.alwaysApply === true) return "Always On"

  if (frontmatter.globs && frontmatter.globs.trim() !== "")
    return `Glob: ${String(frontmatter.globs)}`
  return "Model Decision"
}

import type { RuleItem } from "../types/RuleItem"
import { detectUmbrellaType } from "../antigravity/utils/detectUmbrellaType"

export function getAntigravityReference(item: RuleItem) {
  const ruleName = item.rel.replace(/\.mdc$/, "").replace(/\//g, "-")
  const { isWorkflow } = detectUmbrellaType(item, item.rel)

  return isWorkflow
    ? `@.agent/workflows/${String(ruleName)}.md`
    : `@.agent/rules/${String(ruleName)}.md`
}

/**
 * @param {Array<{ rel: string, content: string }>} items
 * @returns {Array<{ category: string, subgroups: Array<{ subcategory: string, rules: Array<{ rel: string, content: string }> }> }>}
 */

interface RuleItem {
  rel: string
  content: string
  [key: string]: unknown
}

export function groupByCategoryAndSubcategory(items: RuleItem[]) {
  const map: Record<string, Record<string, RuleItem[]>> = {}
  for (const item of items) {
    const parts = item.rel.split("/")
    const category = parts.length === 1 ? "root" : parts[0]
    const subcategory = parts.length >= 3 ? parts[1] : ""

    map[category!] = map[category!] ?? {}

    map[category!]![subcategory!] = map[category!]![subcategory!] ?? []

    map[category!]![subcategory!]!.push(item)
  }

  const categories = Object.keys(map).sort((a: string, b: string) => {
    if (a === "root") return -1
    if (b === "root") return 1
    return a.localeCompare(b)
  })
  return categories.map((category: string) => {
    const subcatMap = map[category]!
    const subcategories = Object.keys(subcatMap).sort((a: string, b: string) => {
      // Keep empty subcategory first for readability (rules directly under category).
      if (a === "") return -1
      if (b === "") return 1
      return a.localeCompare(b)
    })

    const subgroups = subcategories.map((subcategory: string) => {
      const rules = subcatMap[subcategory]!.slice().sort((a: RuleItem, b: RuleItem) =>
        a.rel.localeCompare(b.rel),
      )
      return { subcategory, rules }
    })

    return { category, subgroups }
  })
}

import { ENTRYPOINTS } from "../constants/ENTRYPOINTS"
import { ROOT_FILE_TO_SEGMENT } from "../constants/ROOT_FILE_TO_SEGMENT"

export function groupByTopSegment<T extends { rel: string }>(
  items: T[],
) {
  const map: Record<string, T[]> = {}
  for (const item of items) {
    const parts = item.rel.split("/")

    let seg = "misc"
    if (parts.length === 1) {
      if (item.rel in ROOT_FILE_TO_SEGMENT)
        seg = ROOT_FILE_TO_SEGMENT[item.rel as keyof typeof ROOT_FILE_TO_SEGMENT]
      else if (ENTRYPOINTS.has(item.rel)) seg = "entrypoints"
      else seg = "misc"
    } else {
      seg = parts[0] || "misc"
    }
    map[seg] = map[seg] ?? []

    map[seg]!.push(item)
  }

  for (const seg of Object.keys(map)) {
    map[seg]!.sort((a: T, b: T) => a.rel.localeCompare(b.rel))
  }

  return map
}

import { defaultGetRuleRef } from "./defaultGetRuleRef"
import { getOneLineDescription } from "./getOneLineDescription"
import { groupByTopSegment } from "./groupByTopSegment"
import { normalizeRel } from "./normalizeRel"
import { renderRouter } from "./renderRouter"
import type { RenderIndexOnlyOptions } from "../types/RenderIndexOnlyOptions"
import type { RuleItem } from "../types/RuleItem"

/**
 * Generic index-only renderer engine. Emits only rule references (path + short description).
 * No rule bodies. No IDE-specific logic; wrappers (skins) pass options/callbacks.
 *
 * @param {Array<{ rel: string, frontmatter: object, content: string }>} bundle
 * @param {RenderIndexOnlyOptions} options
 * @returns {string}
 */

export function renderIndexOnly(bundle: RuleItem[], options: RenderIndexOnlyOptions = {}) {
  const maxChars = typeof options.maxChars === "number" ? options.maxChars : 15_000

  const onLimit = options.onLimit === "truncate" ? "truncate" : "error"

  const includeShortSummary = options.includeShortSummary === true

  const referencePrefix = options.referencePrefix ?? "@rules/"

  const title = options.title ?? "# Index"

  const headerIntro = options.headerIntro ?? ""

  const embedContent = options.embedContent ?? ""

  const getRuleRef =
    typeof options.getRuleRef === "function"
      ? options.getRuleRef
      :  
        defaultGetRuleRef(referencePrefix)

  const getRuleBadges =
    typeof options.getRuleBadges === "function" ? options.getRuleBadges : () => []
  const attempt = (withShortSummary: boolean) => {
    const items = bundle

      .map((item: RuleItem) => ({
        rel: normalizeRel(item.rel),

        frontmatter: item.frontmatter ?? {},

        content: item.content ?? "",
      }))

      .filter((i: RuleItem) => i.rel?.endsWith(".mdc"))

      .sort((a: RuleItem, b: RuleItem) => a.rel.localeCompare(b.rel))

    const groups = groupByTopSegment(items)
    const header = [title, "", headerIntro].join("\n").trimEnd()

    const embedded = embedContent ? `\n\n---\n\n${embedContent.trim()}\n\n---` : ""
    const router = renderRouter(groups, {
      getRuleRef,

      getRuleBadges,
      getOneLineDesc: (item: RuleItem) => getOneLineDescription(item, { includeShortSummary: withShortSummary }),
    })
    return `${header}${embedded}\n\n${router}\n`
  }
  const primary = attempt(includeShortSummary)
  if (primary.length <= maxChars) return primary
  if (includeShortSummary) {
    const downgraded = attempt(false)
    if (downgraded.length <= maxChars) return downgraded
  }

  if (onLimit === "truncate") {
    return primary.slice(0, maxChars)
  }

  throw new Error(
    `Index exceeded size budget: ${primary.length} > ${maxChars} chars. ` +
      "Reduce descriptions/summaries or increase maxChars.",
  )
}

interface RuleItem {
  rel: string
  content: string
  frontmatter?: Record<string, unknown>
  [key: string]: unknown
}

export function renderRouter(
  groups: Record<string, RuleItem[]>,
  {
    getRuleRef,
    getRuleBadges,
    getOneLineDesc,
  }: {
    getRuleRef: (item: RuleItem) => string
    getRuleBadges: (item: RuleItem) => string[]
    getOneLineDesc: (item: RuleItem) => string
  },
) {
  const segments = Object.keys(groups).sort((a: string, b: string) => {
    if (a === "entrypoints") return -1
    if (b === "entrypoints") return 1
    return a.localeCompare(b)
  })
  const lines = [
    "## Rules index (router)",
    "",
    "Each entry points to the source rule file. Content is intentionally not inlined here.",
    "",
    "### Sections",
    "",
    segments.join(" · "),
    "",
  ]
  for (const seg of segments) {
    lines.push(seg === "entrypoints" ? "### entrypoints (start here)" : `### ${seg}`)
    lines.push("")

    for (const item of groups[seg] || []) {
      const ref = getRuleRef(item)

      const description = getOneLineDesc(item)

      const primary = `- \`${ref}\` — ${description}`
      lines.push(primary)

      const badges = getRuleBadges(item)

      if (badges.length > 0) {
        lines.push(`  (${badges.join(", ")})`)
      }
    }

    lines.push("")
  }

  return lines.join("\n")
}

import type { RuleFrontmatter } from "../../types/RuleFrontmatter"

/**
 * Convert to Windsurf rule frontmatter format
 * @param {object} frontmatter - Parsed MDC frontmatter
 * @returns {string} - Formatted frontmatter for Windsurf
 */
export function formatWindsurfFrontmatter(frontmatter: RuleFrontmatter) {
  const lines = ["---"]
  if (frontmatter.description) {
    lines.push(`description: "${frontmatter.description}"`)
  }

  if (frontmatter.globs) {
    lines.push(`globs: "${frontmatter.globs}"`)
  }

  if (frontmatter.alwaysApply !== undefined) {
    lines.push(`alwaysApply: ${String(frontmatter.alwaysApply)}`)
  }

  if (frontmatter.priority) {
    lines.push(`priority: ${frontmatter.priority}`)
  } else {
    // Default priority based on alwaysApply
    lines.push(`priority: ${frontmatter.alwaysApply ? "high" : "medium"}`)
  }

  lines.push("---")
  return lines.join("\n")
}

export const matchValue = (content: string, pattern: RegExp | string) => {
  if (typeof pattern === "string") {
    const match = content.match(pattern)
    return match?.[1]?.trim() ?? ""
  }
  const match = pattern.exec(content)
  return match?.[1]?.trim() ?? ""
}
